class ServerConfig:
    """Server configuration loaded from environment variables."""

    DEFAULTS = {
        'HOST': '127.0.0.1',
        'PORT': '9000',
        'LOG_LEVEL': 'INFO',
        'DATA_DIR': './data',
    }

    def __init__(self):
        self._config = {}
        for key, default in self.DEFAULTS.items():
            env_key = f'SERVER_{key}'
            self._config[key] = os.environ.get(env_key, default)
        os.makedirs(self._config['DATA_DIR'], exist_ok=True)

    def get(self, key, default=None):
        return self._config.get(key, default)


def parse_args(argv):
    """Parse command-line arguments for the server."""
    result = {'command': None, 'host': None, 'port': None, 'daemon': False}
    i = 0
    while i < len(argv):
        arg = argv[i]
        if arg in ('start', 'stop', 'status', 'restart'):
            result['command'] = arg
        elif arg == '--host' and i + 1 < len(argv):
            i += 1
            result['host'] = argv[i]
        elif arg == '--port' and i + 1 < len(argv):
            i += 1
            result['port'] = argv[i]
        elif arg == '--daemon':
            result['daemon'] = True
        i += 1
    return result


class PIDFile:
    """Manages a PID file for tracking the server process."""

    def __init__(self, path):
        self.path = path

    def write(self, pid):
        with open(self.path, 'w') as f:
            f.write(str(pid))

    def read(self):
        try:
            with open(self.path, 'r') as f:
                return int(f.read().strip())
        except FileNotFoundError:
            return None

    def remove(self):
        try:
            os.remove(self.path)
        except FileNotFoundError:
            pass


class Logger:
    """File-based logger with timestamped entries and rotation."""

    def __init__(self, log_path, max_bytes=1_000_000):
        self.log_path = log_path
        self.max_bytes = max_bytes
        os.makedirs(os.path.dirname(log_path) or '.', exist_ok=True)

    def _write(self, level, message):
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        entry = f'[{timestamp}] {level}: {message}\n'
        with open(self.log_path, 'a') as f:
            f.write(entry)
        self._rotate()

    def _rotate(self):
        try:
            if os.path.getsize(self.log_path) > self.max_bytes:
                os.replace(self.log_path, self.log_path + '.1')
        except FileNotFoundError:
            pass

    def info(self, message):
        self._write('INFO', message)

    def error(self, message):
        self._write('ERROR', message)

    def warning(self, message):
        self._write('WARNING', message)


class ConnectionHandler(threading.Thread):
    """Handles a single client connection in its own thread."""

    def __init__(self, client_id, callback):
        super().__init__(daemon=True)
        self.client_id = client_id
        self.callback = callback

    def run(self):
        self.callback(self.client_id)


class ThreadPool:
    """A simple thread pool with a task queue."""

    def __init__(self, max_workers=4):
        self.max_workers = max_workers
        self._queue = queue.Queue()
        self._workers = []
        for _ in range(max_workers):
            t = threading.Thread(target=self._worker, daemon=True)
            t.start()
            self._workers.append(t)

    def _worker(self):
        while True:
            task = self._queue.get()
            if task is None:
                break
            try:
                task()
            except Exception:
                pass
            finally:
                self._queue.task_done()

    def submit(self, task):
        self._queue.put(task)

    def shutdown(self):
        for _ in self._workers:
            self._queue.put(None)
        for t in self._workers:
            t.join(timeout=5)


class RequestRouter:
    """Routes command strings to registered handler functions."""

    def __init__(self):
        self._routes = {}

    def route(self, command):
        def decorator(func):
            self._routes[command] = func
            return func
        return decorator

    def dispatch(self, request):
        parts = request.strip().split()
        if not parts:
            raise ValueError('Empty request')
        command = parts[0]
        args = parts[1:]
        if command not in self._routes:
            raise ValueError(f'Unknown command: {command}')
        return self._routes[command](args)


class TCPServer:
    """A TCP server that listens for connections."""

    def __init__(self, host='127.0.0.1', port=9000):
        self.host = host
        self.port = port
        self._running = False
        self._socket = None

    @property
    def is_running(self):
        return self._running

    def start(self):
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self._socket.bind((self.host, self.port))
        self._socket.listen(5)
        self._running = True

    def stop(self):
        self._running = False
        if self._socket:
            try:
                self._socket.close()
            except OSError:
                pass
            self._socket = None

    def accept_connections(self):
        while self._running:
            try:
                client_sock, addr = self._socket.accept()
                yield client_sock, addr
            except OSError:
                break


class ServerProtocol:
    """JSON-based protocol with length-prefixed messages."""

    @staticmethod
    def encode(message):
        payload = json.dumps(message).encode('utf-8')
        header = struct.pack('!I', len(payload))
        return header + payload

    @staticmethod
    def decode(data):
        return json.loads(data.decode('utf-8'))

    @staticmethod
    def read_message(sock):
        header = sock.recv(4)
        if len(header) < 4:
            return None
        length = struct.unpack('!I', header)[0]
        data = b''
        while len(data) < length:
            chunk = sock.recv(length - len(data))
            if not chunk:
                return None
            data += chunk
        return ServerProtocol.decode(data)

    @staticmethod
    def send_message(sock, message):
        sock.sendall(ServerProtocol.encode(message))


class ServerClient:
    """Client for connecting to the server and sending commands."""

    def __init__(self, host='127.0.0.1', port=9000):
        self.host = host
        self.port = port
        self._socket = None

    def connect(self):
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._socket.connect((self.host, self.port))

    def send_command(self, command, **args):
        request = {'command': command, 'args': args}
        ServerProtocol.send_message(self._socket, request)
        return ServerProtocol.read_message(self._socket)

    def close(self):
        if self._socket:
            self._socket.close()
            self._socket = None


class DataStore:
    """SQLite-backed key-value store with timestamps."""

    def __init__(self, db_path):
        self.db_path = db_path
        self._init_db()

    def _connect(self):
        return sqlite3.connect(self.db_path)

    def _init_db(self):
        with self._connect() as conn:
            conn.execute(
                'CREATE TABLE IF NOT EXISTS store '
                '(key TEXT PRIMARY KEY, value TEXT, updated_at TEXT)'
            )

    def set(self, key, value):
        with self._connect() as conn:
            conn.execute(
                'INSERT OR REPLACE INTO store (key, value, updated_at) '
                'VALUES (?, ?, ?)',
                (key, value, datetime.now().isoformat())
            )

    def get(self, key):
        with self._connect() as conn:
            row = conn.execute(
                'SELECT value FROM store WHERE key = ?', (key,)
            ).fetchone()
            return row[0] if row else None

    def delete(self, key):
        with self._connect() as conn:
            conn.execute('DELETE FROM store WHERE key = ?', (key,))

    def list_keys(self):
        with self._connect() as conn:
            rows = conn.execute('SELECT key FROM store').fetchall()
            return [row[0] for row in rows]

    def get_stats(self):
        with self._connect() as conn:
            count = conn.execute('SELECT COUNT(*) FROM store').fetchone()[0]
        size = os.path.getsize(self.db_path) if os.path.exists(self.db_path) else 0
        return {'total_keys': count, 'db_size_bytes': size}


class HealthMonitor:
    """Tracks server health metrics with a sliding request window."""

    def __init__(self):
        self._start_time = time.time()
        self.connections_total = 0
        self.connections_active = 0
        self.errors_total = 0
        self._request_times = deque(maxlen=1000)

    def record_connection(self):
        self.connections_total += 1
        self.connections_active += 1

    def record_disconnect(self):
        self.connections_active = max(0, self.connections_active - 1)

    def record_request(self):
        self._request_times.append(time.time())

    def record_error(self):
        self.errors_total += 1

    def get_status(self):
        now = time.time()
        rpm = sum(1 for t in self._request_times if now - t < 60)
        return {
            'uptime': now - self._start_time,
            'connections_total': self.connections_total,
            'connections_active': self.connections_active,
            'requests_per_minute': rpm,
            'errors_total': self.errors_total,
        }

    def is_healthy(self):
        return self.errors_total < 100 and self.connections_active < 1000


